type DisperseMode int //gd:BoneTwistDisperser3D.DisperseMode

const (
	// Assign amounts so that they monotonically increase from 0.0 to 1.0, ensuring all weights are equal. For example, with five joints, the amounts would be 0.2, 0.4, 0.6, 0.8, and 1.0 starting from the root bone.
	DisperseModeEven DisperseMode = 0
	// Assign amounts so that they monotonically increase from 0.0 to 1.0, based on the length of the bones between joint segments. See also [SetWeightPosition].
	//
	// [SetWeightPosition]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetWeightPosition
	DisperseModeWeighted DisperseMode = 1
	// You can assign arbitrary amounts to the joint list. See also [SetJointTwistAmount].
	//
	// When [IsEndBoneExtended] is false, a child of the reference bone exists solely to determine the twist axis, so its custom amount has absolutely no effect at all.
	//
	// [IsEndBoneExtended]: https://pkg.go.dev/graphics.gd/classdb/#Instance.IsEndBoneExtended
	// [SetJointTwistAmount]: https://pkg.go.dev/graphics.gd/classdb/#Instance.SetJointTwistAmount
	DisperseModeCustom DisperseMode = 2
)
